const body = $json.body || $json;
const message = body.message || body;
const toolCall = message.toolCall || body.toolCall || body.tool_call || {};
const fn = toolCall.function || toolCall;
let args = fn.arguments || toolCall.arguments || body.arguments || {};
if (typeof args === 'string') {
  try {
    args = JSON.parse(args);
  } catch (error) {
    args = { raw: args };
  }
}
const rawToolName = fn.name || toolCall.name || body.tool_name || args.tool_name || 'unknown_tool';
const allowedTools = ['check_availability', 'create_booking', 'upsert_contact', 'cancel_booking', 'transfer_call'];
const toolName = allowedTools.includes(rawToolName) ? rawToolName : 'unknown_tool';
const call = message.call || body.call || {};
const baseUrl = process.env.VOICE_TOOL_BASE_URL || 'https://example.com/voice-tools';
return [{
  json: {
    call_id: call.id || body.call_id || body.callId || 'unknown_call',
    tool_call_id: toolCall.id || body.tool_call_id || null,
    tool_name: toolName,
    original_tool_name: rawToolName,
    args,
    target_url: `${baseUrl}/${toolName}`,
    received_at: new Date().toISOString()
  }
}];

const tool = $('Normalize Tool Call').item.json;
const result = $json;
return [{
  json: {
    ok: true,
    call_id: tool.call_id,
    tool_name: tool.tool_name,
    results: [
      {
        toolCallId: tool.tool_call_id,
        result: result.result || result.message || result
      }
    ]
  }
}];

const body = $json.body || $json;
const message = body.message || body;
const call = message.call || body.call || {};
return [{
  json: {
    call_id: call.id || body.call_id || body.callId || 'unknown_call',
    customer_phone: call.customer?.number || body.customer_phone || body.phone || '',
    assistant_id: call.assistantId || body.assistant_id || '',
    transcript: message.transcript || body.transcript || '',
    recording_url: message.recordingUrl || body.recording_url || '',
    ended_reason: message.endedReason || body.ended_reason || '',
    received_at: new Date().toISOString()
  }
}];

const call = $('Normalize Call End').item.json;
const rawSummary = $json.summary || $json.result || $json.output || $json;
const summary = typeof rawSummary === 'string' ? { summary: rawSummary } : rawSummary;
return [{
  json: {
    call_id: call.call_id,
    customer_phone: call.customer_phone,
    assistant_id: call.assistant_id,
    transcript: call.transcript,
    recording_url: call.recording_url,
    ended_reason: call.ended_reason,
    summary: summary.summary || summary.text || '',
    lead_status: summary.lead_status || 'needs_review',
    next_action: summary.next_action || 'Review transcript before follow-up.',
    fields_to_update: summary.fields_to_update || {},
    received_at: call.received_at
  }
}];
